/**
 * Chunk Question Model
 *
 * Stores synthesized questions for chunks (ATLAS-KG Phase 2+).
 * Each chunk has 3-5 answerable questions pre-generated by LLM.
 * Also stores document-level questions (aggregated from all chunks).
 * Enables question-based retrieval and query matching.
 */

import mongoose, { Schema, model } from 'mongoose';
import { uuidv7 } from '../mongo/base-document.js';
import { tenantIsolationPlugin } from '../mongo/plugins/tenant-isolation.plugin.js';
import { ModelRegistry } from '../model-registry.js';

// ─── Document Interface ──────────────────────────────────────────────────

export interface IChunkQuestion {
  _id: string;
  tenantId: string;
  indexId: string;
  documentId: string;
  /** Chunk ID (null for document-level questions) */
  chunkId: string | null;
  /** Generated question text */
  question: string;
  /** Question scope (chunk-level or document-level) */
  scope: 'chunk' | 'document';
  /** Question type/category */
  questionType: 'factual' | 'conceptual' | 'procedural' | 'analytical' | 'other';
  /** Confidence score (0-1) */
  confidence: number;
  /** Embedding vector ID in vector store */
  vectorId: string | null;
  /** Position among questions for this chunk/document */
  questionIndex: number;
  /** Metadata */
  metadata: Record<string, unknown> | null;
  status: string;
  _v: number;
  createdAt: Date;
  updatedAt: Date;
}

// ─── Schema ──────────────────────────────────────────────────────────────

const ChunkQuestionSchema = new Schema<IChunkQuestion>(
  {
    _id: { type: String, default: uuidv7 },
    tenantId: { type: String, required: true },
    indexId: { type: String, required: true },
    documentId: { type: String, required: true },
    chunkId: { type: String, default: null }, // null for document-level questions
    question: { type: String, required: true },
    scope: {
      type: String,
      required: true,
      enum: ['chunk', 'document'],
      default: 'chunk',
    },
    questionType: {
      type: String,
      required: true,
      enum: ['factual', 'conceptual', 'procedural', 'analytical', 'other'],
      default: 'other',
    },
    confidence: { type: Number, default: 1.0, min: 0, max: 1 },
    vectorId: { type: String, default: null },
    questionIndex: { type: Number, required: true, default: 0 },
    metadata: { type: Schema.Types.Mixed, default: null },
    status: { type: String, required: true, default: 'pending' },
    _v: { type: Number, default: 1 },
  },
  { timestamps: true, collection: 'chunk_questions' },
);

// ─── Plugins ─────────────────────────────────────────────────────────────

ChunkQuestionSchema.plugin(tenantIsolationPlugin);

// ─── Indexes ─────────────────────────────────────────────────────────────

// Index-level queries with tenant isolation
ChunkQuestionSchema.index({ tenantId: 1, indexId: 1 });
// Chunk-level queries with tenant isolation
ChunkQuestionSchema.index({ tenantId: 1, indexId: 1, chunkId: 1 }, { sparse: true });
// Document-level queries
ChunkQuestionSchema.index({ documentId: 1 });
// Scope-based filtering (chunk vs document questions)
ChunkQuestionSchema.index({ tenantId: 1, indexId: 1, scope: 1 });
// Question type filtering with tenant isolation
ChunkQuestionSchema.index({ tenantId: 1, indexId: 1, questionType: 1 });
// Status filtering for embedding workflow
ChunkQuestionSchema.index({ status: 1 });
// Vector ID lookup (sparse since not all questions may be embedded)
ChunkQuestionSchema.index({ vectorId: 1 }, { sparse: true });

// ─── Model ───────────────────────────────────────────────────────────────

// Register with ModelRegistry for dual-database support
ModelRegistry.registerModelDefinition('ChunkQuestion', ChunkQuestionSchema, 'searchaicontent');

export const ChunkQuestion =
  (mongoose.models.ChunkQuestion as any) ||
  model<IChunkQuestion>('ChunkQuestion', ChunkQuestionSchema);
